import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "../admin/Admin.css";
import "./Student.css";

export default function StudentExercises() {
  const navigate = useNavigate();
  const [tab, setTab] = useState("assignments");
  const [assignments, setAssignments] = useState([]);
  const [quizzes, setQuizzes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [submitModal, setSubmitModal] = useState(null);
  const [submitContent, setSubmitContent] = useState("");
  const [submitting, setSubmitting] = useState(false);

  useEffect(() => {
    const fetchAll = async () => {
      setLoading(true);
      try {
        const [aRes, qRes] = await Promise.all([
          api.get("/student/assignments").catch(() => ({ data: { data: [] } })),
          api.get("/student/quizzes").catch(() => ({ data: { data: [] } })),
        ]);
        setAssignments(aRes.data.data || []);
        setQuizzes(qRes.data.data || []);
      } catch { }
      finally { setLoading(false); }
    };
    fetchAll();
  }, []);

  const isExpired = (deadline) => deadline && new Date(deadline) < new Date();
  const isNearDeadline = (deadline) => {
    if (!deadline) return false;
    const diff = new Date(deadline) - new Date();
    return diff > 0 && diff < 24 * 60 * 60 * 1000 * 2; // trong 2 ngày
  };

  const handleSubmit = async () => {
    if (!submitContent.trim()) { toast.error("Nhập nội dung bài làm"); return; }
    setSubmitting(true);
    try {
      await api.post(`/assignments/${submitModal.id}/submit`, { content: submitContent });
      toast.success("Nộp bài thành công!");
      setSubmitModal(null);
      setSubmitContent("");
      const r = await api.get("/student/assignments").catch(() => ({ data: { data: [] } }));
      setAssignments(r.data.data || []);
    } catch { toast.error("Không thể nộp bài"); }
    finally { setSubmitting(false); }
  };

  if (loading) return <div className="page-loading"><div className="spinner" /></div>;

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Bài tập & Kiểm tra</h1>
        <p>Bài tập và bài kiểm tra được giao trong các lớp của bạn</p>
      </div>

      <div className="teacher-tabs">
        <button className={`ttab ${tab === "assignments" ? "active" : ""}`} onClick={() => setTab("assignments")}>
          📋 Bài tập ({assignments.length})
        </button>
        <button className={`ttab ${tab === "quizzes" ? "active" : ""}`} onClick={() => setTab("quizzes")}>
          📝 Bài kiểm tra ({quizzes.length})
        </button>
      </div>

      {tab === "assignments" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {assignments.length === 0
            ? <div className="empty-state"><p>Chưa có bài tập nào được giao</p></div>
            : assignments.map(a => {
              const expired = isExpired(a.deadline);
              const near = isNearDeadline(a.deadline);
              return (
                <div key={a.id} className={`assignment-card ${expired ? "expired" : near ? "near-deadline" : ""}`}>
                  <div className="assignment-card-left">
                    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                      <span className={`badge ${a.examType === "IELTS" ? "badge-blue" : "badge-green"}`}>{a.examType}</span>
                      <span className="badge badge-orange">{a.examPart || a.type}</span>
                      {near && !expired && <span className="badge badge-yellow">⚠️ Sắp hết hạn</span>}
                      {expired && <span className="badge badge-red">❌ Hết hạn</span>}
                      {a.submitted && <span className="badge badge-green">✅ Đã nộp</span>}
                    </div>
                    <h4>{a.title}</h4>
                    <p className="assign-desc">{a.description?.slice(0, 120)}{a.description?.length > 120 ? "..." : ""}</p>
                    <div className="assign-meta">
                      <span>🏆 Điểm tối đa: {a.maxScore}</span>
                      {a.deadline && (
                        <span style={{ color: expired ? "var(--danger)" : near ? "var(--warning)" : "var(--gray-400)" }}>
                          ⏰ Hạn nộp: {new Date(a.deadline).toLocaleString("vi-VN")}
                        </span>
                      )}
                      {a.score !== null && a.score !== undefined && (
                        <span style={{ color: "var(--success)", fontWeight: 600 }}>Điểm: {a.score}/{a.maxScore}</span>
                      )}
                    </div>
                    {a.comment && (
                      <div style={{ background: "var(--success-light)", borderRadius: 6, padding: "6px 10px", marginTop: 6, fontSize: "0.78rem", color: "var(--gray-700)" }}>
                        💬 Nhận xét: {a.comment}
                      </div>
                    )}
                  </div>
                  <div className="assignment-card-right">
                    {!a.submitted && !expired && (
                      <button className="btn btn-primary btn-sm" onClick={() => setSubmitModal(a)}>
                        📤 Nộp bài
                      </button>
                    )}
                    {a.submitted && a.score === null && (
                      <span style={{ fontSize: "0.75rem", color: "var(--gray-400)" }}>Chờ chấm điểm</span>
                    )}
                  </div>
                </div>
              );
            })
          }
        </div>
      )}

      {tab === "quizzes" && (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {quizzes.length === 0
            ? <div className="empty-state"><p>Chưa có bài kiểm tra nào</p></div>
            : quizzes.map(q => (
              <div key={q.id} className="assignment-card">
                <div className="assignment-card-left">
                  <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                    <span className={`badge ${q.examType === "IELTS" ? "badge-blue" : "badge-green"}`}>{q.examType}</span>
                    <span className="badge badge-purple">{q.examPart}</span>
                    {q.timeLimit && <span className="badge badge-yellow">⏱ {q.timeLimit} phút</span>}
                    {q.completed && <span className="badge badge-green">✅ Đã làm</span>}
                  </div>
                  <h4>{q.title}</h4>
                  {q.instructions && <p className="assign-desc">{q.instructions?.slice(0, 100)}</p>}
                  {q.score !== null && q.score !== undefined && (
                    <p style={{ fontWeight: 600, color: "var(--primary)", marginTop: 6 }}>
                      Điểm: {q.score}/100
                      {q.examType === "IELTS" && ` (Band ~${(q.score / 100 * 9).toFixed(1)})`}
                      {q.examType === "TOEIC" && ` (~${Math.round(q.score / 100 * 990)}/990)`}
                    </p>
                  )}
                </div>
                <div className="assignment-card-right">
                  {q.completed
                    ? <span className="badge badge-gray">Đã nộp</span>
                    : <button className="btn btn-primary btn-sm" onClick={() => navigate(`/student/quiz/${q.id}`)}>
                        Làm bài →
                      </button>
                  }
                </div>
              </div>
            ))
          }
        </div>
      )}

      {/* Modal nộp bài */}
      {submitModal && (
        <div className="modal-overlay" onClick={() => setSubmitModal(null)}>
          <div className="modal" style={{ maxWidth: 580 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>📤 Nộp bài — {submitModal.title}</h3>
              <button className="modal-close" onClick={() => setSubmitModal(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div style={{ background: "var(--gray-50)", borderRadius: 8, padding: "10px 14px", fontSize: "0.82rem", color: "var(--gray-600)", marginBottom: 12 }}>
                {submitModal.description}
              </div>
              <div className="form-group">
                <label>Bài làm của bạn *</label>
                <textarea rows={8} value={submitContent} onChange={e => setSubmitContent(e.target.value)}
                  placeholder={submitModal.type === "writing" ? "Viết bài của bạn tại đây..." : "Mô tả bài nói của bạn hoặc dán link recording..."}
                  style={{ padding: "10px 12px", border: "1.5px solid var(--gray-200)", borderRadius: 8, resize: "vertical", outline: "none", fontFamily: "inherit", lineHeight: 1.7 }} />
              </div>
              <p style={{ fontSize: "0.75rem", color: "var(--gray-400)" }}>
                Hạn nộp: {submitModal.deadline ? new Date(submitModal.deadline).toLocaleString("vi-VN") : "Không giới hạn"}
              </p>
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setSubmitModal(null)}>Hủy</button>
              <button className="btn btn-primary" onClick={handleSubmit} disabled={submitting}>
                {submitting ? <span className="spinner" /> : "📤 Nộp bài"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
